class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        left, right = 1, maxSum
        while left < right:
            mid = (left + right + 1) // 2
            total = 0
            for i in range(n):
                total += max(1, mid - abs(i - index))
            if total <= maxSum:
                left = mid
            else:
                right = mid - 1
        return left
```
